import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

const WeeklyBarChart = ({ data, dataKey, fillColor, title }) => {
  const hasData = data && data.some(item => item[dataKey] > 0);

  if (!hasData) {
    return <p className="text-center text-gray-500">Log some food to see your weekly {dataKey} trend.</p>;
  }

  return (
    <div>
      <h3 className="text-lg font-semibold text-center mb-4 text-gray-600">{title}</h3>
      <ResponsiveContainer width="100%" height={300}>
        <BarChart
          data={data}
          margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
        >
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis />
          <Tooltip formatter={(value) => `${value.toFixed(1)}g`} />
          <Legend />
          <Bar dataKey={dataKey} fill={fillColor} name={dataKey.charAt(0).toUpperCase() + dataKey.slice(1)} />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default WeeklyBarChart;
